let researchContent = '';

if (agentResponse.output) {
  researchContent = agentResponse.output;
} else if (agentResponse.text) {
  researchContent = agentResponse.text;
} else if (agentResponse.content) {
  researchContent = agentResponse.content;
} else if (typeof agentResponse === 'string') {
  researchContent = agentResponse;
} else {
  researchContent = JSON.stringify(agentResponse, null, 2);
}

// Parse sections if possible (simple text parsing)
const sections = {
  executiveSummary: extractSection(researchContent, 'EXECUTIVE SUMMARY:', 'MAIN THESIS'),
  mainThesis: extractSection(researchContent, 'MAIN THESIS/ANGLE FOR VIDEO:', 'VIDEO HOOK'),
  videoHook: extractSection(researchContent, 'VIDEO HOOK:', 'KEY POINTS'),
  keyPoints: extractSection(researchContent, 'KEY POINTS FOR VIDEO:', 'COMPELLING STATISTICS'),
  statistics: extractSection(researchContent, 'COMPELLING STATISTICS:', 'EXPERT INSIGHTS'),
  expertInsights: extractSection(researchContent, 'EXPERT INSIGHTS/NOTABLE QUOTES:', 'CASE STUDIES'),
  caseStudies: extractSection(researchContent, 'CASE STUDIES/EXAMPLES:', 'HISTORICAL CONTEXT'),
  historicalContext: extractSection(researchContent, 'HISTORICAL CONTEXT:', 'CURRENT STATE'),
  currentState: extractSection(researchContent, 'CURRENT STATE:', 'CONTROVERSIES'),
  controversies: extractSection(researchContent, 'CONTROVERSIES/DEBATES:', 'VISUAL CONTENT'),
  visualSuggestions: extractSection(researchContent, 'VISUAL CONTENT SUGGESTIONS:', 'NARRATIVE STRUCTURE'),
  narrativeStructure: extractSection(researchContent, 'NARRATIVE STRUCTURE FOR VIDEO:', 'SOURCES CONSULTED'),
  sources: extractSection(researchContent, 'SOURCES CONSULTED:', null)
};

function extractSection(text, startMarker, endMarker) {
  const startIndex = text.indexOf(startMarker);
  if (startIndex === -1) return '';

  const contentStart = startIndex + startMarker.length;
  let contentEnd = text.length;

  if (endMarker) {
    const endIndex = text.indexOf(endMarker, contentStart);
    if (endIndex !== -1) {
      contentEnd = endIndex;
    }
  }

  return text.substring(contentStart, contentEnd).trim();
}

